func:
// Clears the shared flow-context baseline BEFORE each Start EGM press, so
// the conveyor-simulator function always re-captures a fresh baseline from
// wherever the robot actually is right now. Without this, pressing Start,
// Stop, jogging the robot elsewhere, then Start again would keep computing
// targets relative to the OLD baseline - EGMActJoint sets the correction
// range's center to the robot's CURRENT position at each new session, so a
// stale baseline could compute a target outside the +-10deg egm_minmax
// range and fault the session.
flow.set('egmConvBaseline', undefined);
flow.set('egmConvStart', undefined);
return msg;

// Stands in for a real belt encoder / vision feed: every throttled EGM
// telemetry frame (fed straight into this node's input), recompute where
// the simulated "part on the conveyor" currently is and offset joint 5
// (wrist bend) to track it - chosen over joint 6 (wrist roll) because it
// produces a visible arc at the end-effector instead of a hard-to-see
// roll-in-place, while still only being a small motion. Stays well inside
// the +-10deg egm_minmax correction range set in MainModuleEGM.mod's
// RunEgmJoint. A real integration would replace ONLY this function's body
// with a read of the actual encoder/vision position - everything
// downstream (output 1 into gofa-egm-move) is unchanged.
//
// Baseline is flow-scoped (not node-scoped) context, cleared by the
// "Reset simulated conveyor baseline" node right before every Start EGM
// press - so it's always freshly captured from the CURRENT position at
// session start, never stale from a previous session.
var joints = msg.payload && msg.payload.joints;
if (!Array.isArray(joints) || joints.length !== 6) return [null, null];

if (flow.get('egmConvBaseline') === undefined) {
    flow.set('egmConvBaseline', joints);
    flow.set('egmConvStart', Date.now());
}

var baseline = flow.get('egmConvBaseline');
var elapsed = (Date.now() - flow.get('egmConvStart')) / 1000;

// One simulated "part" every 6s, smooth sweep +-7deg (inside the +-10deg
// clamp) rather than a hard reset - a real encoder position doesn't jump,
// so neither should this stand-in.
var period = 6;
var amplitudeDeg = 7;
var offsetDeg = amplitudeDeg * Math.sin(2 * Math.PI * elapsed / period);

var target = baseline.slice();
target[4] = target[4] + offsetDeg;

// Pick window: the simulated part is "in reach" near the sweep's center
// crossing (ascending) - illustrates where you'd trigger a real gofa-grip
// call in a production conveyor cell. No gripper is mounted on this robot,
// so this only reports the window, it doesn't fire a real grip.
var inPickWindow = Math.abs(offsetDeg) < 0.75;

var moveMsg = { payload: target };
var statusMsg = { payload: { inPickWindow: inPickWindow, offsetDeg: Math.round(offsetDeg * 100) / 100 } };
return [moveMsg, statusMsg];
